# Meeting Minutes — one-time setup & launch
# Open PowerShell in your app folder and paste this entire block

New-Item -ItemType Directory -Force -Path "templates" | Out-Null

# app.py
[System.IO.File]::WriteAllBytes("app.py", [System.Convert]::FromBase64String(""))

# requirements.txt
[System.IO.File]::WriteAllBytes("requirements.txt", [System.Convert]::FromBase64String("Zmxhc2s+PTMuMC4wCmFudGhyb3BpYz49MC40MC4wCg=="))

# templates/index.html
[System.IO.File]::WriteAllBytes("templates\index.html", [System.Convert]::FromBase64String(""))

# autostart.bat
[System.IO.File]::WriteAllBytes("autostart.bat", [System.Convert]::FromBase64String(""))

Write-Host ""
Write-Host "  Files created. Installing dependencies..." -ForegroundColor Cyan
pip install flask anthropic -q --disable-pip-version-check
Write-Host "  Done." -ForegroundColor Green
Write-Host ""
if (-not $env:ANTHROPIC_API_KEY) {
    $key = Read-Host "  Anthropic API key (sk-ant-...)"
    $env:ANTHROPIC_API_KEY = $key
    Set-Content -Path ".apikey" -Value $key -NoNewline
}
Write-Host ""
python app.py
